import * as React from 'react';
import { updateContexts as updateWebToolsContexts, hub as webToolsHub } from '@dep305/codemaker-web-tools';

import { validate } from '../services/auth';
import { useAuthStore } from '../store/auth';
import { useChatConfig } from '../store/chat-config';
import { useChatApplyStore } from '../store/chatApply';
import { IDE, useExtensionStore } from '../store/extension';
import { versionCompare } from '../utils/common';
import { initProvider } from '../telemetry/otel';

export default function AuthProvider() {
  const accessToken = useAuthStore((state) => state.accessToken);
  const ide = useExtensionStore((state) => state.IDE);
  const setAuthExtends = useAuthStore((state) => state.setAuthExtends);
  const setMemoryConfig = useChatConfig((state) => state.setMemoryConfig);
  const chatModels = useChatConfig((state) => state.chatModels);

  const setEnableNewApply = useChatApplyStore((state) => state.setEnableNewApply);
  const disableNewApply = useChatApplyStore((state) => state.disableNewApply);
  const pluginVersion = useExtensionStore((state) => state.codeMakerVersion) || '';
  const setPkgNamespace = useAuthStore((state) => state.setPkgNamespace);

  React.useEffect(() => {
    async function effect() {
      if (!accessToken) {
        return;
      }
      const data = await validate();
      setAuthExtends({
        department: data.department,
        department_code: data.department_code,
        c_unrestrict: data.c_unrestrict
      });
      setPkgNamespace(data.pkg_namespace);
      if (data.department.includes('技术中心-效能研发部')) {
        try {
          initProvider();
        } catch (e) {
          console.warn('[otel] init failed', e);
        }
      }
      setMemoryConfig({
        visible: !!data.codebase_compress,
      });
      let newApplyVersion = false;
      if (ide === IDE.VisualStudioCode) {
        newApplyVersion = versionCompare('2.5.8', pluginVersion) >= 0;
      } else if (ide === IDE.JetBrains && pluginVersion) {
        try {
          const jbVersion = pluginVersion.split('-')[1];
          newApplyVersion = versionCompare('2.3.9', jbVersion) >= 0;
        } catch {
          newApplyVersion = false;
        }
      }
      setEnableNewApply(!disableNewApply && data.new_apply_enable && newApplyVersion);
      if (data.track_enable) {
        updateWebToolsContexts({ enabled: true });
        webToolsHub.configureScope((scope) => {
          const context = {
            gateway: data.gateway,
            code_generate_model: data.code_generate_model,
            code_review_url: data.code_review_proxy,
            code_lint_url: data.code_lint_proxy,
            code_search_url: data.code_search,
            department: data.department,
            department_code: data.department_code,
            pkg_namespace: data.pkg_namespace,
          }
          scope.setExtras(context);
          scope.setTag("source", "web-ui");
          updateWebToolsContexts(context);
        });
      } else {
        updateWebToolsContexts({ enabled: false });
      }

    }
    effect();
  }, [
    chatModels,
    setAuthExtends,
    accessToken,
    ide,
    disableNewApply,
    pluginVersion,
    setEnableNewApply,
    setMemoryConfig,
  ]);

  return null;
}

import { ReactNode, useCallback, useMemo, useRef, useState } from 'react';
import {
  Box,
  Text,
  Button,
  Popover,
  PopoverBody,
  PopoverContent,
  PopoverTrigger,
  PopoverHeader,
  CloseButton,
  Tooltip,
  useOutsideClick,
  VStack,
  Icon,
} from '@chakra-ui/react';
import SelectWithTooltip, { SelectOption } from '../../components/SelectWithTooltip';
import { RiFileEditLine, RiQuestionnaireLine, RiToolsLine } from 'react-icons/ri';
import { FiFileText } from "react-icons/fi";
import { useChatConfig } from '../../store/chat-config';
import { LuListTodo } from 'react-icons/lu';
import { IoTerminalOutline } from 'react-icons/io5';
import { IoMdBook } from 'react-icons/io';
import MCPConfigCollapse from './MCPConfigCollapse';
import { TbBrandNetbeans, TbWand } from 'react-icons/tb';
import { useChatTerminalStore } from '../../store/chatTerminal';
import MCPSettingModel from './MCPSettingModel';
import { IDE, useExtensionStore } from '../../store/extension';
import { versionCompare } from '../../utils/common';
import { LuMessageSquareTextIcon } from '../../components/Icon';
import { AiOutlineQuestionCircle } from 'react-icons/ai';
import { useChatAttach, useChatStore } from '../../store/chat';
import { AttachType } from '../../store/attaches';
import { useFilteredAttach } from './ChatTypeAhead/Attach/Hooks/useFilteredAttach';
import {
  updateCurrentSession,
  useCurrentSession,
} from '../../hooks/useCurrentSession';
import { usePostMessage } from '../../PostMessageProvider';
import userReporter from '../../utils/report';
import { UserEvent } from '../../types/report';
import { useSkillsStore } from '../../store/skills';
import MiniButton from '../../components/MiniButton';
import DevspaceCollapse from './DevspaceCollapse';

enum EAutoConfig {
  AutoApprove = 'autoApprove',
  AutoApply = 'autoApply',
  AutoExecute = 'autoExecute',
  AutoTodo = 'autoTodo',
}

function ChatFunctionalToolbar({ disabled = false }: { disabled?: boolean }) {
  const [isOpen, setIsOpen] = useState(false);
  const [mcpSettingOpen, setMcpSettingOpen] = useState(false);

  const popoverRef = useRef<HTMLDivElement>(null);
  const popoverContentRef = useRef<HTMLDivElement>(null);
  const ide = useExtensionStore((state) => state.IDE);
  const pluginVersion =
    useExtensionStore((state) => state.codeMakerVersion) || '';
  const attachs = useChatAttach((state) => state.attachs);
  const filterAttachHook = useFilteredAttach();
  const syncHistory = useChatStore((state) => state.syncHistory);
  const { postMessage } = usePostMessage();
  const codebaseChatMode = useChatStore((state) => state.codebaseChatMode);

  const supportNewApply = useMemo(() => {
    let newApplyVersion = false;
    if (ide === IDE.VisualStudioCode) {
      newApplyVersion = versionCompare('2.5.8', pluginVersion) >= 0;
    } else if (ide === IDE.JetBrains && pluginVersion) {
      try {
        const jbVersion = pluginVersion.split('-')[1];
        newApplyVersion = versionCompare('2.3.9', jbVersion) >= 0;
      } catch {
        newApplyVersion = false;
      }
    }
    return newApplyVersion;
  }, [ide, pluginVersion]);

  const currentSession = useCurrentSession();

  const [compressConfig, setCompressConfig] = useChatConfig((state) => [
    state.compressConfig,
    state.setMemoryConfig,
  ]);
  const [enableTerminal, setEnableTerminal] = useChatTerminalStore((state) => [
    state.enableTerminal,
    state.setEnableTerminal,
  ]);

  const config = useChatConfig((state) => ({
    autoApprove: state.autoApprove,
    autoApply: state.autoApply,
    autoExecute: state.autoExecute,
    autoTodo: state.autoTodo,
    updateAutoApprove: state.updateAutoApprove,
    updateAutoApply: state.updateAutoApply,
    updateAutoExecute: state.updateAutoExecute,
    updateAutoTodo: state.updateAutoTodo,
  }));

  const [
    enableCodeMapSearch,
    setEnableCodeMapSearch,
    enableKnowledgeLibSearch,
    setEnableKnowledgeLibSearch,
    enableEditableMode,
    setEnableEditableMode,
    enableUserQuestion,
    setEnableUserQuestion,
  ] = useChatConfig((state) => [
    state.enableCodeMapSearch,
    state.setEnableCodeMapSearch,
    state.enableKnowledgeLibSearch,
    state.setEnableKnowledgeLibSearch,
    state.enableEditableMode,
    state.setEnableEditableMode,
    state.enableUserQuestion,
    state.setEnableUserQuestion,
  ]);

  const enableSkills = useChatConfig((state) => state.enableSkills);
  const setEnableSkills = useChatConfig((state) => state.setEnableSkills);

  const skills = useSkillsStore((state) => state.skills);

  useOutsideClick({
    ref: popoverRef,
    handler: (e) => {
      // 检查点击目标是否在 PopoverContent 内部
      const target = e.target as Node;
      if (popoverContentRef.current?.contains(target)) {
        return;
      }
      // 检查点击目标是否在 Portal 渲染的下拉菜单内（SelectWithTooltip 的下拉菜单）
      const targetElement = e.target as HTMLElement;
      const dropdown = targetElement.closest('[data-select-dropdown="true"]');
      if (dropdown) {
        return;
      }
      // 检查是否点击了 selectOption
      const clickTarget = targetElement?.getAttribute?.('data-target') || '';
      if (['selectOption'].includes(clickTarget)) {
        return;
      }
      setIsOpen(false);
    },
  });

  const openExtensionSetting = useCallback(() => {
    postMessage({
      type: 'OPEN_EXTENSION_SETTING_AUTHORIZATION_PATH',
    });
  }, [postMessage]);

  const onReportAutoConfig = useCallback(
    (autoType: string, enable: boolean) => {
      userReporter.report({
        event: UserEvent.CODE_CHAT_ACCEPT_AUTO_MODE,
        extends: {
          autoApply: config.autoApply,
          autoExecute: config.autoExecute,
          autoApprove: config.autoApprove,
          [autoType]: enable,
        },
      });
    },
    [config.autoApply, config.autoApprove, config.autoExecute],
  );

  const renderSwitchItem = useCallback(
    (item: {
      title: string;
      icon: ReactNode;
      value: boolean;
      tooltip?: string;
      lebalTooltips?: string;
      onChange?: (val: boolean) => void;
      autoConfigKey?: EAutoConfig;
      autoValue?: boolean;
      autoTip?: ReactNode;
      onAutoChange?: (val: boolean) => void;
      alwaysEnabled?: boolean; // 始终启用模式，只有"启用"和"启用(Auto)"两个选项
    }) => {
      const hasAutoOption = item.autoConfigKey && item.onAutoChange !== undefined;

      // 确定 Select 的值
      // alwaysEnabled 模式下没有 'off' 选项，直接根据 autoValue 判断
      const selectValue = item.alwaysEnabled
        ? (item.autoValue ? 'auto' : 'on')
        : (!item.value ? 'off' : (item.autoValue ? 'auto' : 'on'));

      // Build options array
      const selectOptions: SelectOption[] = item.alwaysEnabled
        ? [{ value: 'on', label: '启用' }]
        : [
            { value: 'off', label: '关闭' },
            { value: 'on', label: '启用' },
          ];

      if (hasAutoOption) {
        // For autoTip, extract text or use a simplified version
        let tooltipText = '自动模式';
        let tooltipTitle = '自动模式';

        if (item.autoConfigKey === EAutoConfig.AutoApprove) {
          tooltipTitle = '自动读取';
          tooltipText = '开启后，智聊过程将自动进行目录/文件授权，可通过配置忽略目录来保护敏感文件';
        } else if (item.autoConfigKey === EAutoConfig.AutoExecute) {
          tooltipTitle = '自动执行';
          tooltipText = '智聊过程需运行的命令将自动执行，可通过配置忽略命令来规避高危操作';
        } else if (item.autoConfigKey === EAutoConfig.AutoApply) {
          tooltipTitle = '自动应用';
          tooltipText = '智聊过程的代码修改将自动应用，可通过消息回撤来恢复变更';
        } else if (item.autoConfigKey === EAutoConfig.AutoTodo) {
          tooltipTitle = '自动规划';
          tooltipText = '智聊过程生成的plan执行过程全自动，无需手动确认';
        } else if (typeof item.autoTip === 'string') {
          tooltipText = item.autoTip;
        }

        selectOptions.push({
          value: 'auto',
          label: '启用(Auto)',
          tooltipTitle: tooltipTitle,
          tooltip: tooltipText
        });
      }

      return (
        <Box
          display="flex"
          justifyContent="space-between"
          alignItems="center"
          paddingBottom={2}
        >
          <Box fontSize={12} display="flex" alignItems="center">
            {item?.icon}
            <Text marginLeft={item.icon ? 2 : 0} fontSize="12px">
              {item.title}
            </Text>
            {item.lebalTooltips && (
              <Tooltip label={item.lebalTooltips} placement="top">
                <Box
                  display="inline-flex"
                  alignItems="center"
                  ml={1}
                  cursor="help"
                >
                  <Icon
                    as={AiOutlineQuestionCircle}
                    w="14px"
                    h="14px"
                    color="gray.500"
                  />
                </Box>
              </Tooltip>
            )}
          </Box>
          <Box display="flex" alignItems="center">
            <SelectWithTooltip
              size="xs"
              width="90px"
              options={selectOptions}
              value={selectValue}
              isDisabled={disabled}
              onChange={(e) => {
                const value = e.target.value;
                const isEnabled = value !== 'off';
                const isAuto = value === 'auto';

                // 先更新启用状态
               if (!item.alwaysEnabled && item.value !== isEnabled && item.onChange) {
                  item.onChange(isEnabled);
                }

                // 如果有 auto 选项，更新 auto 状态
                if (hasAutoOption && item.autoValue !== isAuto) {
                  if (isAuto) {
                    onReportAutoConfig(item.autoConfigKey!, isAuto);
                  }
                  item.onAutoChange!(isAuto);
                }
              }}
            />
          </Box>
        </Box>
      );
    },
    [disabled, onReportAutoConfig],
  );

  const renderAutoMemoryItem = useCallback(() => {
    if (!compressConfig.visible) return null;

    return renderSwitchItem({
      title: 'Memory 工具',
      icon: <LuMessageSquareTextIcon w="16px" h="16px" color="white" />,
      value: compressConfig.enable,
      lebalTooltips:
        '当上下文窗口占用达到100%时，自动进行内容压缩生成memory，增强仓库智聊对上下文的记忆能力',
      onChange: (val) => {
        setCompressConfig({ enable: val });
      },
    });
  }, [compressConfig, renderSwitchItem, setCompressConfig]);

  const renderSkillsItem = useCallback(() => {
    if (skills.length === 0) return null;

    return renderSwitchItem({
      title: 'Skills 工具',
      icon: <TbWand size={16} />,
      value: enableSkills,
      lebalTooltips:
        '加载本地 Skills 文件，根据需求自动匹配并激活对应的专业指导，支持 ~/.claude/skills、.claude/skills、.codemaker/skills 目录',
      onChange: (val) => {
        setEnableSkills(val);
      },
    });
  }, [skills.length, enableSkills, renderSwitchItem, setEnableSkills]);

  return (
    <Box ref={popoverRef} data-tour="chat-functional-toolbar">
      <Popover placement="top" isOpen={isOpen} isLazy lazyBehavior="unmount">
        <PopoverTrigger>
          <MiniButton
            // size="sm"
            // // color={hasAnyAutoEnabled ? "blue.300" : "text.secondary"}
            // bg={isLight ? '#F2F2F2' : '#2C2C2C'}
            // h="28px"
            // minH="28px"
            // _hover={{
            //   bg: isLight ? '#F2F2F2' : '#2C2C2C',
            //   color: 'blue.300',
            // }}
            // px="2"
            // fontSize="12px"
            // fontWeight="normal"
            onClick={() => !disabled && setIsOpen(!isOpen)}
            disabled={disabled}
            style={{
              opacity: disabled ? 0.4 : 1,
              pointerEvents: disabled ? 'none' : 'auto',
            }}
          >
            <Tooltip label="仓库聊天时，自动支持开启的工具类型" placement="top">
              <Box>
                <RiToolsLine size={'16px'} />
              </Box>
            </Tooltip>
          </MiniButton>
        </PopoverTrigger>
        <PopoverContent w={'330px'} ref={popoverContentRef} maxH="80vh" display="flex" flexDirection="column">
          <PopoverHeader
            display="flex"
            justifyContent="space-between"
            alignItems="center"
            borderBottom="1px solid"
            borderColor="gray.200"
            _dark={{ borderColor: 'gray.600' }}
            py={2}
            px={3}
            flexShrink={0}
          >
            <Text fontSize="13px" fontWeight="medium">
              工具配置
            </Text>
            <CloseButton size="sm" onClick={() => setIsOpen(false)} />
          </PopoverHeader>
          <Box
            className="show-scrollbar"
            flex="1"
            minH="0"
            overflowY="auto"
          >
            <PopoverBody display="flex" flexDirection="column" p="2">
              <VStack align="stretch" py={1}>
              {renderSwitchItem({
                title: '仓库文件读取',
                icon: <FiFileText size={16} />,
                value: true, // 始终启用
                alwaysEnabled: true, // 只有"启用"和"启用(Auto)"两个选项
                autoConfigKey: EAutoConfig.AutoApprove,
                autoValue: config.autoApprove,
                onAutoChange: (val) => {
                  onReportAutoConfig(EAutoConfig.AutoApprove, val);
                  config.updateAutoApprove(val);
                },
              })}
              {!['openspec', 'speckit'].includes(codebaseChatMode || '') && renderSwitchItem({
                title: 'Plan Mode',
                icon: <LuListTodo size={16} />,
                value: currentSession?.data?.enablePlanMode || false,
                lebalTooltips:
                  '将复杂需求分解成可执行的任务，提供plan面板可视化思路与进度，可随时介入调整计划方向',
                onChange: (val) => {
                  console.log('更新plan');
                  updateCurrentSession((session) => {
                    if (session.data) {
                      session.data.enablePlanMode = val;
                      requestAnimationFrame(syncHistory)
                    }
                  });
                },
                autoConfigKey: EAutoConfig.AutoTodo,
                autoValue: config.autoTodo,
                autoTip: '开启后，智聊过程生成的plan执行过程全自动，无需手动确认',
                onAutoChange: (val) => {
                  onReportAutoConfig(EAutoConfig.AutoTodo, val);
                  config.updateAutoTodo(val);
                },
              })}
              {renderSwitchItem({
                title: '代码地图检索',
                icon: <TbBrandNetbeans size={16} />,
                tooltip:
                  '开启检索代码地图工具后，检索知识库工具将同步启用，因为检索代码地图工具是基于知识库的内容进行拓展分析',
                value: enableCodeMapSearch,
                lebalTooltips:
                  '根据需求智能检索云端接入的代码地图，检索相关的代码调用与片段辅助智聊生成代码',
                onChange: (val) => {
                  if (val) {
                    setEnableKnowledgeLibSearch(val);
                  } else {
                    filterAttachHook.filterAttachesByAttachType(attachs, [
                      AttachType.CodeBase,
                    ]);
                  }
                  setEnableCodeMapSearch(val);
                },
              })}
              {renderSwitchItem({
                title: '知识库检索',
                icon: <IoMdBook size={16} />,
                value: enableKnowledgeLibSearch,
                lebalTooltips:
                  '根据需求智能调用有权限的知识库，检索相关的知识片段辅助智聊回答问题',
                onChange: (val) => {
                  setEnableKnowledgeLibSearch(val);
                  if (!val) {
                    setEnableCodeMapSearch(val);
                    filterAttachHook.filterAttachesByAttachType(attachs, [
                      AttachType.CodeBase,
                      AttachType.Docset,
                    ]);
                  }
                },
              })}
              {supportNewApply &&
                renderSwitchItem({
                  title: '代码Apply',
                  icon: <RiFileEditLine size={16} />,
                  value: enableEditableMode,
                  lebalTooltips:
                    '将生成的代码智能应用到目标代码文件，提供清晰的Changes与Apply Diff',
                  onChange: (val) => {
                    setEnableEditableMode(val);
                  },
                  autoConfigKey: EAutoConfig.AutoApply,
                  autoValue: config.autoApply,
                  autoTip: '开启后，智聊过程的代码修改将自动应用，可通过消息回撤来恢复变更',
                  onAutoChange: (val) => {
                    onReportAutoConfig(EAutoConfig.AutoApply, val);
                    config.updateAutoApply(val);
                  },
                })}
              {renderSwitchItem({
                title: '执行CMD',
                icon: <IoTerminalOutline size={16} />,
                value: enableTerminal,
                lebalTooltips:
                  '根据需求生成并执行终端命令，实时回显执行结果，自动诊断并修正错误指令，直至任务成功',
                onChange: (val) => {
                  setEnableTerminal(val);
                },
                autoConfigKey: EAutoConfig.AutoExecute,
                autoValue: config.autoExecute,
                autoTip: (
                  <span>
                    开启后，智聊过程需运行的命令将自动执行，可通过
                    <Button
                      variant="link"
                      color="#776fff"
                      onClick={(e) => {
                        e.stopPropagation();
                        openExtensionSetting();
                      }}
                    >
                      配置忽略命令
                    </Button>
                    来规避高危操作
                  </span>
                ),
                onAutoChange: (val) => {
                  onReportAutoConfig(EAutoConfig.AutoExecute, val);
                  config.updateAutoExecute(val);
                },
              })}
              {renderAutoMemoryItem()}
              {renderSkillsItem()}
              {renderSwitchItem({
                title: '需求澄清工具',
                icon: <RiQuestionnaireLine size={'16'} color="white" />,
                value: enableUserQuestion,
                lebalTooltips: '针对不明确的问题，仓库智聊会主动向你提问并提供相关选项，助力澄清需求',
                onChange: (val) => {
                  setEnableUserQuestion(val);
                },
              })}
              <DevspaceCollapse />
              <MCPConfigCollapse setMcpSettingOpen={setMcpSettingOpen} />
            </VStack>
          </PopoverBody>
          </Box>
        </PopoverContent>
      </Popover>
      {/* 注入组件 */}
      <MCPSettingModel
        isOpen={mcpSettingOpen}
        onClose={() => setMcpSettingOpen(false)}
      />
    </Box>
  );
}

export default ChatFunctionalToolbar;

