            gridTemplateRows="1fr"
          >
            {showCodebaseFeedBack && feedbackDetail ? (
              <CodeBaseFeedback
                feedbackDetail={feedbackDetail}
                onResetFeedback={() => {
                  setShowCodebaseFeedBack(false);
