 * {
 *    "choices": [],
 *    ""
 * }
 * 非正常返回，格式可能是：
 * {
 *    "data": "xxxxx error"
 * }
 *
 */

let latestMessage: Record<string, unknown> | BMLatestMessage | undefined;

