            //   }
            // }
            if (needContinue && continueCount < MAX_CONTINUE_COUNT) {
              userReporter.report({
                event: UserEvent.TOOLCALL_STOP_BY_LENGTH,
                extends: {
                  model: data.model,
                  max_tokens: data.max_tokens,
                },
              });
              if (chunkTimeoutId) {
                clearInterval(chunkTimeoutId);
              }
              needContinue = false;
              continueCount++;
              if (toolCalls && toolCalls.length) {
                const preResponseMessage: ChatMessage = {
                  role: ChatRole.Assistant,
                  content: responseText || '-',
                };
                const nextData = {
                  ...promptData,
                  messages: [
                    ...data.messages,
                    preResponseMessage,
                    SEPERATE_TOOL_CALL_MESSAGE,
                  ],
                };
                otel.stopChatSpan(span, {
                  messages: [preResponseMessage],
                  usage: {
                    prompt_tokens: promptTokens,
                    completion_tokens: completionTokens,
                    total_tokens: totalTokens,
                    cache_creation_input_tokens: cacheCreationInputTokens,
                    cache_read_input_tokens: cacheReadInputTokens,
                  },
                  finish_reason: 'continue',
                });
                options?.onMessage(
                  responseText,
                  false,
                  toolCalls.filter((toolCall) => !!toolCall),
                  completionTokens +
                    promptTokens +
                    cacheCreationInputTokens +
                    cacheReadInputTokens,
                  completionTokens,
                  promptTokens,
                  cacheCreationInputTokens,
                  cacheReadInputTokens,
                  claude37Response,
                  responseId,
                );
                await run(nextData);
                break;
              } else {
                const preResponseMessage: ChatMessage = {
                  role: ChatRole.Assistant,
                  content: responseText || '-',
                };
                const nextData = {
                  ...promptData,
                  messages: [
                    ...data.messages,
                    preResponseMessage,
                    CONTINUOUS_CHAT_MESSAGE_ZH,
                  ],
                };

                otel.stopChatSpan(span, {
                  messages: [preResponseMessage],
                  usage: {
                    prompt_tokens: promptTokens,
                    completion_tokens: completionTokens,
                    total_tokens: totalTokens,
                    cache_creation_input_tokens: cacheCreationInputTokens,
                    cache_read_input_tokens: cacheReadInputTokens,
                  },
                  finish_reason: 'continue',
                });
                options?.onMessage(
                  responseText,
                  false,
                  toolCalls.filter((toolCall) => !!toolCall),
                  completionTokens +
                    promptTokens +
                    cacheCreationInputTokens +
                    cacheReadInputTokens,
                  completionTokens,
                  promptTokens,
                  cacheCreationInputTokens,
                  cacheReadInputTokens,
                  claude37Response,
                  responseId,
                );
                await run(nextData);
                break;
              }
            }
            clearTimeout(chunkTimeoutId);
            otel.stopChatSpan(span, {
              messages: [
                {
                  content: responseText,
                  role: ChatRole.Assistant,
                  tool_calls: toolCalls,
                },
              ],
              usage: {
                prompt_tokens: promptTokens,
                completion_tokens: completionTokens,
                total_tokens: totalTokens,
                cache_creation_input_tokens: cacheCreationInputTokens,
                cache_read_input_tokens: cacheReadInputTokens,
              },
            });
            finish();
            break;
          }

          const textChunk = decoder.decode(chunk.value, { stream: true });
          try {
            const parsedChunk = JSON.parse(textChunk);
            const {
              content,
              tool_calls,
              total_tokens,
              completion_tokens,
              reasoningContent,
              thinkingSignature,
              redactedThinking,
              prompt_tokens,
              cache_creation_input_tokens,
              cache_read_input_tokens,
              response_id,
            } = parsedChunk;
            responseText += content || '';
            if (!responseId) {
              responseId = response_id;
            }
            if (tool_calls) {
              for (const tool of tool_calls) {
                if (!tool) continue;
                const index = tool.index || 0;
                if (!toolCalls[index]) {
                  toolCalls[index] = {
                    id: tool.id || '',
                    function: {
                      arguments: tool.function?.arguments || '',
                      name: getValidToolName(tool.function?.name || ''),
                    },
                    type: tool.type || '',
                  };
                } else {
                  toolCalls[index].id += tool.id || '';
                  toolCalls[index].function.arguments +=
                    tool.function?.arguments || '';
                  toolCalls[index].function.name += getValidToolName(
                    tool.function?.name || '',
                  );
                  toolCalls[index].type += tool.type || '';
                }
                if (toolCalls[index].type.includes('function')) {
                  toolCalls[index].type = 'function';
                }
              }
            }
            if (reasoningContent) {
              claude37Response.reasoning_content += reasoningContent;
            }
            if (thinkingSignature) {
              // Gemini的签名中，content和function都有对应签名，需要一一列举，否则会出现签名不一致的情况
              if ([ChatModel.Gemini25].includes(data?.model as ChatModel)) {
                if (!claude37Response.thinking_signature) {
                  claude37Response.thinking_signature = thinkingSignature;
                }
              } else {
                claude37Response.thinking_signature += thinkingSignature;
              }
            }
            if (redactedThinking) {
              claude37Response.redacted_thinking += redactedThinking;
            }
            if (total_tokens) {
              totalTokens = total_tokens;
              completionTokens = completion_tokens;
              promptTokens = prompt_tokens;
              cacheCreationInputTokens = cache_creation_input_tokens;
              cacheReadInputTokens = cache_read_input_tokens;
            }

            options?.onMessage(
              responseText,
              false,
              toolCalls.filter((toolCall) => !!toolCall),
              completionTokens +
                promptTokens +
                cacheCreationInputTokens +
                cacheReadInputTokens,
              completionTokens,
              promptTokens,
              cacheCreationInputTokens,
              cacheReadInputTokens,
              claude37Response,
              responseId,
            );
          } catch (e) {
            otel.stopChatSpan(span, { error: 'Error parsing chunk' });
            options?.onError(new Error('Error parsing chunk'));
            break;
          }
        }
      } else {
        otel.stopChatSpan(span, { error: 'Stream Error' });
        options?.onError(new Error('Stream Error'));
      }
    } catch (error) {
      if (chunkTimeoutId) {
        clearInterval(chunkTimeoutId);
      }
      otel.stopChatSpan(span, {
        error: error instanceof Error ? error.message : String(error),
      });
      options?.onError(error as Error);
    }
  }

  await run(data);
}

export async function requestDSCodebaseChatStream(
  event: string = UserEvent.CODE_CHAT_CODEBASE,
  data: ChatPromptBody,
  chatRequestUrl = '/proxy/gpt/gpt/text_chat_stream',
  options?: {
    onMessage: (
      message: string,
      done: boolean,
      toolCalls: ToolCall[],
      reasoningText: string,
      totalTokens: number,
      completionTokens: number,
      streamingToolCall: ParsedToolCall | undefined,
    ) => void;
    onError: (error: Error) => void;
    onController?: (controller: AbortController) => void;
    ntesTraceId?: string;
    setError: (type: boolean) => void;
  },
) {
  const abortController = new AbortController();
  options?.onController?.(abortController);
  let responseText = '';
  let totalTokens = 0;
  let completionTokens = 0;
  let toolCalls: ToolCall[] = [];
  let responseReasoningText = '';
  let textContent = '';

  const finish = () => {
    // 兼容下标从 1 开始的情况
    if (toolCalls.length && !toolCalls[0]) {
      toolCalls.shift();
    }
    console.log(responseText);
    options?.onMessage(
      textContent,
      true,
      toolCalls,
      responseReasoningText,
      totalTokens,
      completionTokens,
      undefined,
    );
    abortController.abort();
  };

  async function run(promptData: ChatPromptBody) {
    const url = chatRequestUrl + `/${event}`;
    let chunkTimeoutId: NodeJS.Timeout | null = null;
    try {
      const requestHeaders: any = setRequestHeaders() || {};
      if (options?.ntesTraceId) {
        requestHeaders['ntes-trace-id'] = options?.ntesTraceId;
      }
      const req = new Request(url, {
        method: 'POST',
        headers: requestHeaders,
        body: JSON.stringify(promptData),
        signal: abortController.signal,
      });
      const reqTimeoutId = setTimeout(
        () =>
          abortController.abort({
            name: REQUEST_TIMEOUT_NAME,
            message: StreamError.Timeout,
          }),
        TIMEOUT_MS,
      );
      const res = new Response(await createDeepseekReasonerStream(req));
      if (res.ok) {
        clearTimeout(reqTimeoutId);

        // chunk 回复超时检测
        let lastMessageReceivedTime = new Date().getTime();
        if (chunkTimeoutId) {
          clearInterval(chunkTimeoutId);
        }
        chunkTimeoutId = setInterval(() => {
          if (
            new Date().getTime() - lastMessageReceivedTime >=
            CHAT_STREAM_CHUNK_TIMEOUT
          ) {
            responseText += '\n\n回复超时，请重试';
            userReporter.report({
              event: UserEvent.CODE_CHAT_CHUNK_TIMEOUT,
              extends: {
                model: promptData.model || '',
                ntesTraceId: options?.ntesTraceId,
              },
            });
            webToolsHub.withScope((scope) => {
              scope.setExtras({
                event: UserEvent.CODE_CHAT_CHUNK_TIMEOUT,
                model: promptData.model || '',
                ntesTraceId: options?.ntesTraceId,
                mark: 4,
              });
              webToolsLogger.captureException(
                UserEvent.CODE_CHAT_CHUNK_TIMEOUT,
              );
            });
            options?.setError(true);
            finish();
            if (chunkTimeoutId) {
              clearInterval(chunkTimeoutId);
            }
          }
        }, CHAT_STREAM_CHUNK_TIMEOUT);
        const reader = res.body?.getReader();
        const decoder = new TextDecoder();

        // eslint-disable-next-line
        while (true) {
          const chunk = await reader?.read();
          lastMessageReceivedTime = new Date().getTime();
          if (!chunk || chunk.done) {
            clearTimeout(chunkTimeoutId);
            finish();
            break;
          }

          const textChunk = decoder.decode(chunk.value, { stream: true });
          try {
            const parsedChunk = JSON.parse(textChunk);
            const { text, reasoningText, total_tokens, completion_tokens } =
              parsedChunk;
            responseText += text || '';
            let toolCall = undefined;
            if (responseText) {
              const { parsedToolCalls, parsedContent, streamingToolCall } =
                parseAssistantMessage(responseText);
              if (parsedToolCalls) {
                toolCalls = parsedToolCalls || [];
              }
              if (streamingToolCall) {
                toolCall = streamingToolCall;
              }
              textContent = parsedContent;
            }
            if (reasoningText) {
              responseReasoningText += reasoningText;
            }
            if (total_tokens) {
              totalTokens = total_tokens;
              completionTokens = completion_tokens;
            }

            options?.onMessage(
              textContent,
              false,
              toolCalls,
              responseReasoningText,
              totalTokens,
              completionTokens,
              toolCall,
            );
          } catch (e) {
            options?.onError(new Error('Error parsing chunk'));
            break;
          }
        }
      } else {
        options?.onError(new Error('Stream Error'));
      }
    } catch (error) {
      if (chunkTimeoutId) {
        clearInterval(chunkTimeoutId);
      }
      options?.onError(error as Error);
    }
  }

  await run(data);
}

async function* streamAsyncIterator(stream: ReadableStream) {
  // Get a lock on the stream
  const reader = stream.getReader();

  try {
    while (true) {
      // Read from the stream
      const { done, value } = await reader.read();
      // Exit if we're done
      if (done) return;
      // Else yield the chunk
      yield value;
    }
  } finally {
    reader.releaseLock();
  }
}

// To store message streaming controller
export const ControllerPool = {
  controllers: new Map<string, AbortController>(),

  addController(
    sessionId: string,
    messageIndex: number,
    controller: AbortController,
  ) {
    const key = this.key(sessionId, messageIndex);
    this.controllers.set(key, controller);
    return key;
  },

  stop(sessionId: string, messageIndex: number) {
    const key = this.key(sessionId, messageIndex);
    const controller = this.controllers.get(key);
    controller?.abort();
  },

  remove(sessionId: string, messageIndex: number) {
    const key = this.key(sessionId, messageIndex);
    this.controllers.delete(key);
  },

  key(sessionId: string, messageIndex: number) {
    return `${sessionId}-${messageIndex}`;
  },
};

// To store wait for feedback Q&A
export const FeedbackPool = {
  feedbacks: new Set<string>(),

  add(id: string) {
    this.feedbacks.add(id);
  },

  remove(id: string) {
    this.feedbacks.delete(id);
  },

  getter() {
    return this.feedbacks;
  },

  clear() {
    this.feedbacks = new Set();
  },
};

export const toolCallNames = [
  'list_files_top_level',
  'list_files_recursive',
  'view_source_code_definitions_top_level',
  'read_file',
  'retrieve_code',
  'retrieve_knowledge',
  'use_mcp_tool',
  'access_mcp_resource',
  'edit_file',
  'replace_in_file',
  'excute_command',
  'generate_codewiki_structure',
];

const toolParamNames = [
  'path',
  'search_query',
  'diff',
  'target_file',
  'code_edit',
  'is_create_file',
  'server_name',
  'tool_name',
  'arguments',
  'uri',
  'command',
];

export interface ParsedToolCall {
  name: string;
  params: {
    [propName: string]: string;
  };
}

export function parseAssistantMessage(assistantMessage: string) {
  const toolCalls: ToolCall[] = [];
  let currentTextContent = '';
  let currentToolCall: ParsedToolCall | undefined = undefined;
  const currentToolCallStartIndex = 0;
  let currentParamName: string | undefined = undefined;
  let currentParamValueStartIndex = 0;
  let accumulator = '';
  let streamingToolCall: ParsedToolCall | undefined = undefined;

  for (let i = 0; i < assistantMessage.length; i++) {
    const char = assistantMessage[i];
    accumulator += char;

    if (currentToolCall && currentParamName) {
      const currentParamValue = accumulator.slice(currentParamValueStartIndex);
      const paramClosingTag = `</${currentParamName}>`;
      if (currentParamValue.endsWith(paramClosingTag)) {
        currentToolCall.params[currentParamName] = currentParamValue
          .slice(0, -paramClosingTag.length)
          .trim();
        if (
          streamingToolCall &&
          ['replace_in_file', 'edit_file'].includes(streamingToolCall.name)
        ) {
          streamingToolCall.params[currentParamName] = currentParamValue
            .slice(0, -paramClosingTag.length)
            .trim();
        }
        currentParamName = undefined;
        continue;
      } else if (
        streamingToolCall &&
        ['replace_in_file', 'edit_file'].includes(streamingToolCall.name)
      ) {
        streamingToolCall.params[currentParamName] = currentParamValue.trim();
      } else {
        continue;
      }
    }

    if (currentToolCall) {
      const currentToolValue = accumulator.slice(currentToolCallStartIndex);
      const toolCallClosingTag = `</${currentToolCall.name}>`;
      if (currentToolValue.endsWith(toolCallClosingTag)) {
        toolCalls.push({
          type: 'function',
          id: uniqueId(),
          function: {
            arguments: JSON.stringify(currentToolCall.params),
            name: currentToolCall.name,
          },
        });
        currentToolCall = undefined;
        streamingToolCall = undefined;
        continue;
      } else {
        const possibleParamOpeningTags = toolParamNames.map(
          (name) => `<${name}>`,
        );
        for (const paramOpeningTag of possibleParamOpeningTags) {
          if (accumulator.endsWith(paramOpeningTag)) {
            currentParamName = paramOpeningTag.slice(1, -1);
            currentParamValueStartIndex = accumulator.length;
            break;
          }
        }
        continue;
      }
    }
    let didStartToolCall = false;
    const possibleToolCallOpeningTags = toolCallNames.map(
      (name) => `<${name}>`,
    );
    for (const toolCallOpeningTag of possibleToolCallOpeningTags) {
      if (accumulator.endsWith(toolCallOpeningTag)) {
        currentToolCall = {
          name: toolCallOpeningTag.slice(1, -1),
          params: {},
        };
        streamingToolCall = {
          name: toolCallOpeningTag.slice(1, -1),
          params: {},
        };
        currentTextContent = currentTextContent.slice(
          0,
          -(toolCallOpeningTag.length - 1),
        );
        didStartToolCall = true;
        break;
      }
    }

    if (!didStartToolCall) {
      currentTextContent += char;
    }
  }

  return {
    parsedToolCalls: toolCalls,
    streamingToolCall: streamingToolCall,
    parsedContent: currentTextContent,
    toolCallBreak: toolCalls.length && currentToolCall,
  };
}

