                useChatStore.getState().syncHistory();
              } else {
                set((state) => {
                  if (state.message) {
                    state.message.content = content;
                  } else {
                    console.error(
                      'create bot message before set message content!',
                    );
                  }
                  state.loadingMessage = '';
                });
              }
            },
            onError(error) {
              console.dir(error);
              userReporter.report({
                event: UserEvent.REPLY_EXCEPTION,
                extends: {
                  model,
                  session_id: session._id,
                  error_message: error.message,
                },
              });
              webToolsHub.withScope((scope) => {
                scope.setExtras({
                  event: UserEvent.REPLY_EXCEPTION,
                  model,
                  session_id: session._id,
                  error_message: error.message,
                  mark: 3,
                });
                webToolsLogger.captureException(error);
              });
              let outputContent = get().message.content;
              if (
                error.name === REQUEST_TIMEOUT_NAME ||
                specialErrorPatterns[1].condition(error.message)
              ) {
                get().retryChatStream(
                  id,
                  error.name === REQUEST_TIMEOUT_NAME
                    ? ERetryType.Timeout
                    : ERetryType.AccessLimit,
                );
                return;
              }
              // https://developer.mozilla.org/en-US/docs/Web/API/AbortController/abort
              // error.name 为 AbortError 表示该错误是 abort 触发的
              if (error.name !== ABORT_ERROR_NAME) {
                // 判断 code block 是否闭合，如无闭合，需要先将 code block 闭合
                const isCloseCodeBackticks = checkCodeBlockIsClose(
                  outputContent as string,
                );
                if (!isCloseCodeBackticks) {
                  outputContent += `\n${CODE_BACKTICKS}`;
                }
                if (error.message === StreamError.AuthTokenIsExpired) {
                  window.parent.postMessage(
                    {
                      type: BroadcastActions.GET_INIT_DATA,
                      data: {
                        isExpired: true,
                      },
                    },
                    '*',
                  );
                } else {
                  chatStoreState.setError(true);
                  outputContent += '\n\n 出错了，稍后重试吧';
                }
                if (error.name === REQUEST_TIMEOUT_NAME) {
                  outputContent = `\n\n 消息请求超时`;
                }
                chatStoreState.updateCurrentSession((session) =>
                  session.data?.messages.push({
                    ...DEFAULT_ASSISTANT_MESSAGE,
                    id,
                    content: outputContent,
                  }),
                );
                ControllerPool.remove(sessionId, messageIndex);
                chatStoreState.syncHistory();
                get().reset();
              }
            },
            onController: (abortController) => {
              ControllerPool.addController(
                sessionId,
                messageIndex,
                abortController,
              );
            },
          },
        );
        return;
        // }
      } else if (attachs && attachs.attachType === AttachType.NetworkModel) {
        // 走联网模型逻辑
        get().reset();
        set(() => ({ isStreaming: true }));
        const { model } = attachs as NetworkModel;
        const convertPrompt = await useMaskStore
          .getState()
          .convertToPrompt(content);
        const maskPrompt = {
          id: mask?._id,
          role: ChatRole.User,
          content: convertPrompt,
          attachs: [
            {
              type: ChatMessageAttachType.NetworkModel,
              model: model,
            },
          ],
        };
        const config = useConfigStore.getState().config;
        const len = session.data.messages.length;
        const sendMessages = session.data.messages.slice(
          Math.max(len - config.historyMessageCount - 1, 0),
        );
        const messages = cloneDeep(sendMessages).map((message) => {
          let content = '';
          if (Array.isArray(message.content)) {
            const textContent = message.content.find(
              (item) => item.type === ChatMessageContent.Text,
            );
            content = (textContent as ChatMessageContentText)?.text || '';
          } else {
            content = message.content;
          }
          delete message._originalRequestData;
          // delete message.attachs;
          return {
            ...message,
            content,
          };
        });
        // 非编程模式下，后端不会帮忙补 prompt ，所以需要自己替换和补 prompt
        if (!isProgrammingMode) {
          // 对齐 prompt ，格式为 user->assistant->user
          if (messages[0].role !== ChatRole.Assistant) {
            messages.unshift({
              ...DEFAULT_ASSISTANT_MESSAGE,
              content: '-',
            });
          }
          messages.unshift(maskPrompt);
        }
        if (chatPromptStoreState.prompt) {
          const currentMessageIndex = messages.length - 1;
          messages[currentMessageIndex].content = content;
          chatPromptStoreState.reset();
        }
        const data: ChatPromptBody = {
          messages,
          model,
          max_tokens: chatConfig.max_tokens,
          stream: true,
          // temperature: chatConfig.temperature,
          extra_body: {
            vertexai_tool: {
              google_search_retrieval: {
                open: true,
                dynamic_retrieval_config: {
                  mode: 'MODE_UNSPECIFIED',
                },
              },
            },
          },
        };
        if (isProgrammingMode) {
          // 编程模式下， prompt 让后端补即可，前端不做任何更改 prompt 的操作
          const currentMaskCode = DEFAULT_MASKS.find(
            (i) => i._id === mask?._id,
          )?.code;
          data.prompt_construct = {
            mode: 'default',
            params: {},
          };
          if (currentMaskCode !== '') {
            data.prompt_construct.params = {
              tpl_code: currentMaskCode,
            };
          }
        }
        const chatRequestUrl = isProgrammingMode
          ? '/proxy/gpt/gpt/code_chat_stream'
          : '/proxy/gpt/gpt/text_chat_stream';

        requestNetworkChatStream(options.event, data, chatRequestUrl, {
          onMessage(content, done, webSearch, jsonData) {
            get().setStreamRetryCount(0);
            if (chatStoreState.isError) {
              chatStoreState.setError(false);
            }
            if (done) {
              ControllerPool.remove(sessionId, messageIndex);
              FeedbackPool.add(id);
              set((state) => {
                state.isStreaming = false;
              });
              chatStoreState.updateCurrentSession((session) =>
                session.data?.messages.push({
                  ...get().message,
                  id,
                  content: content,
                  webSearch: webSearch,
                }),
              );
              useChatStore.getState().generateAndUpdateSessionTopic();
              chatStoreState.updateConsumedTokens({
                model: data.model as ChatModel,
                curSession: session,
                promptTokens: jsonData?.metadata?.usage?.prompt_tokens || 0,
                completionTokens:
                  jsonData?.metadata?.usage?.completion_tokens || 0,
                cacheCreationInputTokens:
                  jsonData?.metadata?.usage?.cache_creation_input_tokens || 0,
                cacheReadInputTokens:
                  jsonData?.metadata?.usage?.cache_read_input_tokens || 0,
              });
              chatStoreState.syncHistory();
            } else {
              set((state) => {
                if (state.message) {
                  state.message.content = content;
                } else {
                  console.error(
                    'create bot message before set message content!',
                  );
                }
                state.loadingMessage = '';
              });
            }
          },
          onError(error) {
            console.dir(error);
            userReporter.report({
              event: UserEvent.REPLY_EXCEPTION,
              extends: {
                model,
                session_id: session._id,
                messages: data.messages,
                error_message: error.message,
              },
            });
            webToolsHub.withScope((scope) => {
              scope.setExtras({
                event: UserEvent.REPLY_EXCEPTION,
                model,
                session_id: session._id,
                // messages: data.messages, 数据太大了
                error_message: error.message,
                mark: 4,
              });
              webToolsLogger.captureException(error);
            });
            let outputContent = get().message.content;
            if (
              error.name === REQUEST_TIMEOUT_NAME ||
              specialErrorPatterns[1].condition(error.message)
            ) {
              get().retryChatStream(
                id,
                error.name === REQUEST_TIMEOUT_NAME
                  ? ERetryType.Timeout
                  : ERetryType.AccessLimit,
              );
              return;
            }
            if (error.name !== ABORT_ERROR_NAME) {
              // 判断 code block 是否闭合，如无闭合，需要先将 code block 闭合
              const isCloseCodeBackticks = checkCodeBlockIsClose(
                outputContent as string,
              );
              if (!isCloseCodeBackticks) {
                outputContent += `\n${CODE_BACKTICKS}`;
              }
              if (error.message === StreamError.AuthTokenIsExpired) {
                window.parent.postMessage(
                  {
                    type: BroadcastActions.GET_INIT_DATA,
                    data: {
                      isExpired: true,
                    },
                  },
                  '*',
                );
              }
              outputContent += handleStreamError(error);
              chatStoreState.updateCurrentSession((session) =>
                session.data?.messages.push({
                  ...DEFAULT_ASSISTANT_MESSAGE,
                  id,
                  content: outputContent,
                  group_tokens: 8,
                }),
              );
              ControllerPool.remove(sessionId, messageIndex);
              chatStoreState.syncHistory();
              get().reset();
            }
          },
          onController(abortController) {
            ControllerPool.addController(
              sessionId,
              messageIndex,
              abortController,
            );
          },
        });
        userReporter.report({
          event: UserEvent.CODE_CHAT_START_STREAM,
          extends: {
            content: content,
            mask_id: mask?._id,
            mask_name: mask?.name,
            mask_content: mask?.prompt,
            mask_type: mask?.type,
            model: model,
          },
        });
        return;
      } else if (chatStoreState.chatType === 'codebase') {
        // 走 CodeBase Chat 逻辑
        get().reset();
        set(() => ({ isStreaming: true }));
        let cacheEnable = false;
        if (chatModels[chatConfig.model]?.hasTokenCache) {
          if (codebaseModelMaxTokens[chatConfig.model] > 64 * 1000) {
            cacheEnable = true;
          }
        }

        const compressionSummaryCountAtRequest = (
          session.data?.messages || []
        ).filter((msg) => msg.isCompressionSummary).length;

        const unCompressedMessages = (session.data?.messages || []).filter(
          (msg, index, self) =>
            !msg.isCompressed ||
            (msg.role === ChatRole.Assistant &&
              self?.[index + 1]?.role === ChatRole.Tool &&
              !self?.[index + 1]?.isCompressed),
        );

        const [currentCompressStatus, previousCompressStatus] =
          await Promise.all([
            getCompressSessionStatus(sessionId),
            getPrevCompressSessionStatus(sessionId),
          ]);

        // 判断 tokens 是否超了需要进行截断，遍历 messages+3
        const {
          sendMessages,
          containUserMessage,
          newTruncateStart,
          previousTokens,
          fallbackToSlideWindow,
        } =
          ((previousCompressStatus === SessionStatus.COMPRESSING &&
            currentCompressStatus === SessionStatus.COMPRESSED) ||
            (previousCompressStatus === SessionStatus.COMPRESSED &&
              currentCompressStatus === SessionStatus.COMPRESSING) ||
            (previousCompressStatus === SessionStatus.COMPRESSED &&
              currentCompressStatus === SessionStatus.COMPRESSED)) &&
            compressConfig.enable &&
            compressConfig.visible &&
            !chatModels[chatConfig.model].isPrivate
            ? {
              sendMessages: unCompressedMessages,
              containUserMessage: true,
              newTruncateStart: -1,
              previousTokens: 0,
              fallbackToSlideWindow: false,
            }
            : cacheEnable
              ? truncateMessagesIfNeeded({
                messages: unCompressedMessages,
                model: chatConfig.model,
                codebaseModelMaxTokens,
              })
              : truncatedMessageWithSlideWindow({
                messages: unCompressedMessages,
                model: chatConfig.model,
                codebaseModelMaxTokens,
              });

        if (
          sendMessages.length < unCompressedMessages.length &&
          !chatModels[chatConfig.model].isPrivate &&
          compressConfig.enable &&
          compressConfig.visible &&
          currentCompressStatus !== SessionStatus.COMPRESSING &&
          currentCompressStatus !== SessionStatus.FAILED
        ) {
          console.log('检测到消息截断, 触发强制压缩');
          void chatStoreState.triggerCompression(sessionId);
        }

        if (fallbackToSlideWindow) {
          cacheEnable = false;
        }
        const isReAct = false;
        const codebaseChatSystemPrompt = getCodebaseChatSystemPrompt({
          isReAct,
          effectiveRules,
        });
        sendMessages.unshift({
          role: ChatRole.System,
          content: codebaseChatSystemPrompt,
        });
        // FIX：修复消息上下文丢失的问题
        // OPTIMIZED: 遍历 messages +2
        let filteredMessages = await serializeCodebaseMessages(
          model,
          sendMessages,
          session,
          isReAct,
        );
        // OPTIMIZED: 遍历 messages +1
        filteredMessages = repairToolIdOfMessages(filteredMessages, model);

        // TODO: 不应该在这里重复处理
        if (chatPromptStoreState.prompt && ![
          ...BUILT_IN_PROMPTS.map(prompt => prompt.name),
          ...BUILT_IN_PROMPTS_OPENSPEC_V023.map(openspecPrompt => openspecPrompt.name),
          ...BUILT_IN_PROMPTS_OPENSPEC_V1.map(opsxPrompt => opsxPrompt.name),
          ...BUILT_IN_PROMPTS_SPECKIT.map(speckitPrompt => speckitPrompt.name)
        ].includes(chatPromptStoreState.prompt.name)) {
          const currentMessageIndex = filteredMessages.length - 1;
          filteredMessages[currentMessageIndex].content = content;
          chatPromptStoreState.reset();
        }

        // 处理 mermaid 图表相关的 prompt 替换
        const metaId = prompApp?.runner?.meta?._id || '';
        const MERMAID_PROMPT_MAP: Record<string, string> = {
          '66cf10e1f16cb1260db58a08': ER_PROMPT, // ER 图
          '66cf0a830fe8cbf0be33b162': CLASS_PROMPT, // 类图
          '66d0704b0fe8cbf0be33b170': CFG_PROMPT, // 流程图
          '66e00c47f16cb1260db58a95': SEQUENCE_PROMPT, // 时序图
          '66cd9986f16cb1260db589ec': MINDMAP_PROMPT, // 思维导图
        };

        const targetPrompt = MERMAID_PROMPT_MAP[metaId];
        if (targetPrompt) {
          const lastMessage: any =
            filteredMessages[filteredMessages.length - 1];
          const originalPrompt = prompApp?.runner?.meta?.prompt || '';
          const replaceContent = (text: string) =>
            `${targetPrompt}\n${text.replace(originalPrompt, '')}`;

          if (typeof lastMessage.content === 'string') {
            lastMessage.content = replaceContent(lastMessage.content);
          } else if (
            isArray(lastMessage.content) &&
            lastMessage.content[0]?.type === 'text'
          ) {
            lastMessage.content[0].text = replaceContent(
              lastMessage.content[0].text,
            );
          }

          prompApp.reset();
        }

        const data: ChatPromptBody = {
          messages: filteredMessages,
          model: getAIGWModel(chatConfig.model),
          // max_tokens: chatConfig.max_tokens,
          stream: true,
          tool_choice: chatConfig.model.startsWith('claude')
            ? undefined
            : 'auto',
          tools: getCodebaseChatTools(),
        };

        // 如果用户填了 apikey，则使用用户指定的 apiKey
        if (codeChatApiKey) {
          try {
            const [apiId, apiKey] = codeChatApiKey.split('.');
            if (apiId && apiKey) {
              data.app_id = apiId;
              data.app_key = apiKey;
            }
          } catch (err) {
            console.error(err);
          }
        }
        const chatRequestUrl = '/proxy/gpt/gpt/codebase_chat_stream';
        // Codebase Chat 固定设置 temperature 为 0;
        data.temperature = 0;
        const ntesTraceId = generateTraceId();

        // OPTIMZIED: 遍历 messages +1
        for (const message of data.messages) {
          // 快捷指令发送
          if (message.role === ChatRole.User && message?.shortcutPrompt) {
            message.content = [
              {
                type: ChatMessageContent.Text,
                text:
                  message?.shortcutPrompt.content +
                  '\n' +
                  getContentString(message.content),
              },
            ];
          }
          if (message.tool_calls && !message.tool_calls.length) {
            delete message.tool_calls;
          }
          if (message.specPrompt) {
            const realPrompt = specPromptMap[message.specPrompt];
            if (Array.isArray(message.content)) {
              message.content.unshift({
                type: ChatMessageContent.Text,
                text: realPrompt,
              });
            } else {
              message.content = realPrompt + '\n\n' + message.content;
            }
          }
        }

        // OPTIMIZED: 遍历 messages +1
        reuseDuplicateFileRead({
          messages: data.messages,
          triggerReuse: !cacheEnable || newTruncateStart >= 0,
        });

        useChatConfig.getState().chatModels;
        if (
          chatModels[chatConfig.model]?.hasThinking &&
          getAIGWModel(chatConfig.model)
            ?.toLocaleLowerCase?.()
            ?.includes?.('claude')
        ) {
          // const { maxToken, budgetToken } = calculateTokenBudget(data?.max_tokens || 4096)
          data.max_tokens = 48000;
          const budgetToken = Math.max(
            (data?.max_tokens || CHAT_MIN_TOKENS) / 2,
            1024,
          );

          // OPTIMZIED: 遍历 messages +1
          if (checkThinkingSignatureValid(data.messages)) {
            data.extra_body = {
              thinking: {
                type: 'enabled',
                budget_tokens: budgetToken,
              },
            };
          }
        }

        if (cacheEnable) {
          data.messages = addCacheMarksToMessages(data.messages);
        }

        // 如果由于窗口偏移导致 user 信息丢失，补充进来并告知模型
        if (!containUserMessage) {
          const lastUserIndex = findLastIndex(
            session.data.messages,
            (msg) => msg.role === ChatRole.User,
          );
          if (lastUserIndex >= 0) {
            const lastUserMessage = session.data.messages[lastUserIndex];
            let lastUserContent: ChatMessageContentUnion[] = [];
            if (Array.isArray(lastUserMessage.content)) {
              lastUserContent = lastUserMessage.content;
            } else {
              lastUserContent = [
                {
                  type: ChatMessageContent.Text,
                  text: lastUserMessage.content,
                },
              ];
            }
            data.messages.push({
              role: ChatRole.User,
              content: [
                {
                  type: ChatMessageContent.Text,
                  text:
                    getPlanContextTruncationInstruction() +
                    `<important>\n由于上文长度限制，未展示所有历史对话消息，请不要继续调用多工具，尝试总结并回复，若已有消息不足以得出结论，提示用户提供更多信息\n\n原始题内容如下:</important>\n\n`,
                },
                ...lastUserContent,
              ],
            });
          }
        }

        // 研发空间使用上报
        if (devSpace?._id) {
          userReporter.report({
            event: UserEvent.CODE_CHAT_DEV_SPACE_USED,
            extends: {
              model,
              session_id: session._id,
              dev_space_id: devSpace._id,
              dev_space_name: devSpace.name,
              dev_space_project: devSpace.project,
            },
          });
        }
        const userChatConfig = useChatConfig.getState();
        userReporter.report({
          event: UserEvent.CODE_CHAT_ACCEPT_AUTO_MODE_BEFORE_CHAT,
          extends: {
            autoApply: userChatConfig.autoApply,
            autoExecute: userChatConfig.autoExecute,
            autoApprove: userChatConfig.autoApprove,
            session_id: session._id,
            model,
          },
        });
        // if (content) {
        //   const currentMessageIndex = data.messages.length - 1;
        //   const lastMessage = data.messages[currentMessageIndex];
        //   if (chatType === 'codebase' && lastMessage.role === ChatRole.User) {
        //     const lastMessageContent = lastMessage.content;
        //     if (Array.isArray(lastMessageContent)) {
        //       if (lastMessageContent[0].type === 'text') {
        //         lastMessageContent[0].text = `<user_query>${lastMessageContent[0].text}</user_query>`;
        //       }
        //     }
        //   }
        // }
        if (isReAct) {
          const DEFAULT_MAX_TOKENS = 10240;
          data.max_tokens = data.max_tokens || DEFAULT_MAX_TOKENS;
          delete data.tool_choice;
          delete data.tools;
          requestDSCodebaseChatStream(
            UserEvent.CODE_CHAT_CODEBASE,
            data,
            chatRequestUrl,
            {
              onMessage(
                content,
                done,
                toolCalls,
                reasoningText,
                totalTokens,
                completionTokens,
                streamingToolCall,
              ) {
                get().setStreamRetryCount(0);
                if (chatStoreState.isError) {
                  chatStoreState.setError(false);
                }
                if (done) {
                  if (attachs) {
                    useChatAttach.getState().reset();
                  }
                  ControllerPool.remove(sessionId, messageIndex);
                  FeedbackPool.add(id);
                  const response: {
                    [propName: string]: boolean;
                  } = {};
                  const results: {
                    [propName: string]: {
                      path: string;
                      content: string;
                    };
                  } = {};
                  const allResponsed = false;
                  let isProcessing =
                    toolCalls.length && !allResponsed ? true : false;
                  // 遍历 toolCalls，如果非常规 tool，在 mcp tool 中找一下是否有对应的，恢复一下
                  const MCPServers = useMCPStore
                    .getState()
                    .getAvailableMCPServers();
                  toolCalls.forEach((tool) => {
                    if (!toolCallNames.includes(tool.function.name)) {
                      for (const server of MCPServers) {
                        const targetTool = (server.tools || []).find(
                          (t) => t.name === tool.function.name,
                        );
                        if (targetTool) {
                          tool.function = {
                            name: 'use_mcp_tool',
                            arguments: JSON.stringify({
                              server_name: server.name,
                              tool_name: tool.function.name,
                              arguments: tool.function.arguments,
                            }),
                          };
                          return;
                        }
                        const targetResource = (server.resources || []).find(
                          (t) => t.name === tool.function.name,
                        );
                        if (targetResource) {
                          tool.function = {
                            name: 'access_mcp_resource',
                            arguments: JSON.stringify({
                              server_name: server.name,
                              tool_name: tool.function.name,
                              arguments: tool.function.arguments,
                            }),
                          };
                          return;
                        }
                      }
                    }
                  });

                  if (
                    toolCalls.find((toolCall) =>
                      [
                        'use_mcp_tool',
                        'access_mcp_resource',
                        'edit_file',
                        'reapply',
                        'run_terminal_cmd',
                        'replace_in_file',
                        'ask_user_question',
                      ].includes(toolCall.function.name),
                    )
                  ) {
                    isProcessing = false;
                  }
                  set((state) => {
                    state.isStreaming = false;
                    state.isProcessing = isProcessing;
                    state.isApplying = toolCalls.some((toolCall) =>
                      ['edit_file', 'reapply', 'replace_in_file'].includes(
                        toolCall.function.name,
                      ),
                    );
                  });
                  chatStoreState.updateCurrentSession((session) => {
                    session.data?.messages.push({
                      ...get().message,
                      id,
                      content,
                      tool_calls: toolCalls || [],
                      processing: isProcessing,
                      completion_tokens: completionTokens,
                      response: response,
                      tool_result: results,
                      reasoning_content: reasoningText,
                    });
                    // chatStoreState.updateConsumedTokens(session, data.messages, totalTokens, completionTokens);
                  });
                  onMessageToolCallResponse(
                    session,
                    content,
                    done,
                    toolCalls,
                    totalTokens,
                    completionTokens,
                  );
                  if (MCPServers && MCPServers.length) {
                    let mcpServersUsed: string[] = [];
                    try {
                      mcpServersUsed = MCPServers.map((server) => server.name);
                    } catch {
                      mcpServersUsed = [];
                    }
                    userReporter.report({
                      event: UserEvent.CODE_CHAT_MCP_SESSION_TOKEN_USED,
                      extends: {
                        totalTokens: totalTokens,
                        model: data.model,
                        mcp_servers: mcpServersUsed,
                      },
                    });
                  }
                  if (options.isMCPToolResponse) {
                    userReporter.report({
                      event: UserEvent.CODE_CHAT_MCP_MESSAGE_TOKEN_USED,
                      extends: {
                        totalTokens: totalTokens,
                        model: data.model,
                        mcp_server: options.mcpServerUsed,
                      },
                    });
                  }
                  if (toolCalls.length) {
                    if (!allResponsed) {
                      for (const tool of toolCalls) {
                        if (!response[tool.id]) {
                          let tool_params: any = {};
                          if (tool.function.arguments) {
                            try {
                              tool_params = JSON.parse(tool.function.arguments);
                            } catch (err) {
                              console.error(err);
                              tool_params = {};
                            }
                          }
                          if (
                            tool.function.name === 'use_mcp_tool' ||
                            tool.function.name === 'access_mcp_resource'
                          ) {
                            let params: any = {};
                            try {
                              params = JSON.parse(
                                tool.function.arguments || '{}',
                              );
                            } catch (err) {
                              console.error('解析MCP参数失败', err);
                              params = {};
                            }
                            let autoApprove = false;
                            if (
                              params &&
                              params.server_name &&
                              params.tool_name
                            ) {
                              const targetServer = MCPServers.find(
                                (server) => server.name === params.server_name,
                              );
                              if (targetServer && targetServer.tools) {
                                if (targetServer.autoApprove) {
                                  autoApprove = true;
                                } else if (targetServer.tools) {
                                  const targetTool = targetServer.tools.find(
                                    (tool) => tool.name === params.tool_name,
                                  );
                                  if (targetTool && targetTool.autoApprove) {
                                    autoApprove = true;
                                  }
                                }
                              }
                            } else if (
                              params &&
                              params.server_name &&
                              params.uri
                            ) {
                              const targetServer = MCPServers.find(
                                (server) => server.name === params.server_name,
                              );
                              if (targetServer && targetServer.resources) {
                                if (targetServer.autoApprove) {
                                  autoApprove = true;
                                } else if (targetServer.resources) {
                                  const targetResource =
                                    targetServer.resources.find(
                                      (resource) => resource.uri === params.uri,
                                    );
                                  if (
                                    targetResource &&
                                    targetResource.autoApprove
                                  ) {
                                    autoApprove = true;
                                  }
                                }
                              }
                            }
                            if (autoApprove) {
                              useChatStreamStore
                                .getState()
                                .setIsMCPProcessing(true);
                              otel.saveToolContext(
                                tool.id,
                                tool.function.arguments,
                                get().conversationRound,
                              );
                              window.parent.postMessage(
                                {
                                  type: BroadcastActions.TOOL_CALL,
                                  data: {
                                    tool_name: tool.function.name,
                                    tool_params: params,
                                    tool_id: tool.id,
                                  },
                                },
                                '*',
                              );
                            }
                          } else if (tool.function.name === 'retrieve_code') {
                            otel.saveToolContext(
                              tool.id,
                              tool.function.arguments,
                              get().conversationRound,
                            );
                            window.parent.postMessage(
                              {
                                type: BroadcastActions.TOOL_CALL,
                                data: {
                                  tool_name: tool.function.name,
                                  tool_params: {
                                    question: tool_params.search_query,
                                    collection:
                                      parseAtMentionedCodeBaseByAttach(),
                                  },
                                  tool_id: tool.id,
                                },
                              },
                              '*',
                            );
                          } else if (
                            tool.function.name === 'retrieve_knowledge'
                          ) {
                            otel.saveToolContext(
                              tool.id,
                              tool.function.arguments,
                              get().conversationRound,
                            );
                            window.parent.postMessage(
                              {
                                type: BroadcastActions.TOOL_CALL,
                                data: {
                                  tool_name: tool.function.name,
                                  tool_params: {
                                    // messages: data.messages,
                                    messages: [
                                      {
                                        role: 'user',
                                        content: tool_params.search_query,
                                      },
                                    ],
                                    input: tool_params.search_query,
                                    docsets:
                                      parseAtMentionedKnowledgeBaseByAttach(),
                                    model: data.model,
                                  },
                                  tool_id: tool.id,
                                },
                              },
                              '*',
                            );
                          } else if (tool.function.name === 'read_file') {
                            try {
                              const toolCallParams = JSON.parse(
                                tool.function.arguments || '{}',
                              );
                              // TODO: 需要先给路径做规范化之后再对比
                              const readFilePath = toolCallParams.path.replace(
                                /\\\\/g,
                                '/',
                              );
                              if (readFilePath) {
                                const chatApplyInfo =
                                  useChatApplyStore.getState().chatApplyInfo;
                                const chatApplyItems =
                                  Object.values(chatApplyInfo);
                                const targetApplyItem = chatApplyItems.find(
                                  (item) =>
                                    item.filePath &&
                                    item.filePath === readFilePath,
                                );
                                if (
                                  targetApplyItem &&
                                  targetApplyItem.finalResult
                                ) {
                                  window.postMessage(
                                    {
                                      type: SubscribeActions.TOOL_CALL_RESULT,
                                      data: {
                                        tool_name: 'read_file',
                                        tool_result: {
                                          path: readFilePath,
                                          content: targetApplyItem.finalResult,
                                          isError: false,
                                        },
                                        tool_id: tool.id,
                                      },
                                    },
                                    '*',
                                  );
                                }
                              } else {
                                otel.saveToolContext(
                                  tool.id,
                                  tool.function.arguments,
                                  get().conversationRound,
                                );
                                window.parent.postMessage(
                                  {
                                    type: BroadcastActions.TOOL_CALL,
                                    data: {
                                      tool_name: tool.function.name,
                                      tool_params,
                                      tool_id: tool.id,
                                    },
                                  },
                                  '*',
                                );
                              }
                            } catch (err) {
                              console.error(getErrorMessage(err));
                            }
                          } else if (
                            tool.function.name === terminalCmdFunction
                          ) {
                            if (
                              useChatConfig.getState().autoExecute &&
                              isCommandSafe(
                                useConfigStore.getState().config
                                  .codeBaseCheckCommands,
                                tool_params.command,
                              )
                            ) {
                              otel.saveToolContext(
                                tool.id,
                                tool.function.arguments,
                                get().conversationRound,
                              );
                              window.parent.postMessage(
                                {
                                  type: BroadcastActions.TOOL_CALL,
                                  data: {
                                    tool_name: tool.function.name,
                                    tool_params: {
                                      ...tool_params,
                                      messageId: id,
                                      is_approve: true,
                                    },
                                    tool_id: tool.id,
                                  },
                                },
                                '*',
                              );
                            }
                          } else if (
                            tool.function.name === 'ask_user_question'
                          ) {
                            // ask_user_question 工具在 WebView 中本地处理，不发送 TOOL_CALL 到 IDE
                            // 用户在界面上交互后，通过 AskUserQuestion 组件提交结果
                            console.log(
                              '[Debug] ask_user_question tool intercepted, waiting for user response',
                            );
                          } else {
                            if (
                              [
                                'edit_file',
                                'reapply',
                                'replace_in_file',
                              ].includes(tool.function.name)
                            ) {
                              const filePath = tool_params.target_file;
                              const updateSnippet = tool_params.code_edit;
                              const replaceSnippet = tool_params.diff;
                              const isCreateFile = tool_params.is_create_file;
                              useChatApplyStore
                                .getState()
                                .setChatApplyItem(tool.id, {
                                  filePath,
                                  originalContent: '',
                                  updateSnippet,
                                  replaceSnippet,
                                  type:
                                    tool.function.name === 'replace_in_file'
                                      ? 'replace'
                                      : 'edit',
                                  toolCallId: tool.id,
                                  applying: true,
                                  accepted: false,
                                  isCreateFile,
                                });
                              userReporter.report({
                                event:
                                  tool.function.name === 'replace_in_file'
                                    ? UserEvent.CODE_CHAT_REPLACE_IN_FILE
                                    : UserEvent.CODE_CHAT_EDIT_FILE,
                                extends: {
                                  model,
                                  tool_params: tool_params,
                                  tool_id: tool.id,
                                  tool_name: tool.function.name,
                                },
                              });
                            }
                            otel.saveToolContext(
                              tool.id,
                              tool.function.arguments,
                              get().conversationRound,
                            );
                            window.parent.postMessage(
                              {
                                type: BroadcastActions.TOOL_CALL,
                                data: {
                                  tool_name: tool.function.name,
                                  tool_params,
                                  tool_id: tool.id,
                                },
                              },
                              '*',
                            );
                          }
                        }
                      }
                    } else {
                      get().onUserSubmit(
                        '',
                        {
                          event: UserEvent.CODE_CHAT_CODEBASE,
                        },
                        undefined,
                        response,
                      );
                    }
                  } else {
                    get().resetMessage();
                    get().endConversationRound();
                    window.parent.postMessage(
                      {
                        type: 'WEBVIEW_ACK',
                        data: {
                          event: 'content_completed',
                          payload: session.data,
                        },
                      },
                      '*',
                    );
                  }
                  if (
                    !currentSessionModel ||
                    currentSessionModel !== chatConfig.model
                  ) {
                    // 本次会话没有模型类型或者模型更改了，重新设置模型类型
                    chatStoreState.updateModel(chatConfig.model);
                  }
                  useChatStore.getState().generateAndUpdateSessionTopic();
                  chatStoreState.syncHistory();
                } else {
                  set((state) => {
                    if (state.message) {
                      let codeContent = '';
                      if (streamingToolCall) {
                        if (
                          ['edit_file', 'replace_in_file', 'reapply'].includes(
                            streamingToolCall.name,
                          )
                        ) {
                          const updateSnippet =
                            streamingToolCall.params &&
                            streamingToolCall.params.code_edit;
                          const replaceSnippet =
                            streamingToolCall.params &&
                            streamingToolCall.params.diff;
                          const filePath =
                            streamingToolCall.params &&
                            streamingToolCall.params.target_file;
                          if (filePath && updateSnippet) {
                            // console.log(updateSnippet)
                            // const language = filePath.split('.').slice(-1)[0];
                            codeContent += `\n\n\`\`\`\n${updateSnippet.replace(/\\n/g, '\n')}\n\`\`\``;
                          }
                          if (filePath && replaceSnippet) {
                            // console.log(replaceSnippet)
                            // const language = filePath.split('.').slice(-1)[0];
                            codeContent += `\n\n\`\`\`\n${replaceSnippet.replace(/\\n/g, '\n')}\n\`\`\``;
                          }
                        }
                      }
                      state.message.codeContent = codeContent;
                      state.message.content = content;
                    } else {
                      console.error(
                        'create bot message before set message content!',
                      );
                    }
                    state.loadingMessage = '';
                  });
                }
              },
              onError(error) {
                console.dir(error);
                userReporter.report({
                  event: UserEvent.REPLY_EXCEPTION,
                  extends: {
                    model,
                    session_id: session._id,
                    messages: data.messages,
                    error_message: error.message,
                    ntesTraceId: ntesTraceId,
                  },
                });
                webToolsHub.withScope((scope) => {
                  scope.setExtras({
                    event: UserEvent.REPLY_EXCEPTION,
                    model,
                    session_id: session._id,
                    // messages: data.messages, 数据太大了
                    error_message: error.message,
                    ntesTraceId: ntesTraceId,
                    mark: 5,
                  });
                  webToolsLogger.captureException(error);
                });
                let outputContent = get().message.content;
                if (
                  error.name === REQUEST_TIMEOUT_NAME ||
                  specialErrorPatterns[1].condition(error.message)
                ) {
                  get().retryChatStream(
                    id,
                    error.name === REQUEST_TIMEOUT_NAME
                      ? ERetryType.Timeout
                      : ERetryType.AccessLimit,
                  );
                  return;
                }
                if (error.name !== ABORT_ERROR_NAME) {
                  // 判断 code block 是否闭合，如无闭合，需要先将 code block 闭合
                  const isCloseCodeBackticks = checkCodeBlockIsClose(
                    outputContent as string,
                  );
                  if (!isCloseCodeBackticks) {
                    outputContent += `\n${CODE_BACKTICKS}`;
                  }
                  if (error.message === StreamError.AuthTokenIsExpired) {
                    window.parent.postMessage(
                      {
                        type: BroadcastActions.GET_INIT_DATA,
                        data: {
                          isExpired: true,
                        },
                      },
                      '*',
                    );
                  }
                  outputContent += handleStreamError(error);
                  chatStoreState.updateCurrentSession((session) =>
                    session.data?.messages.push({
                      ...DEFAULT_ASSISTANT_MESSAGE,
                      id,
                      content: outputContent,
                      group_tokens: 8,
                    }),
                  );
                  ControllerPool.remove(sessionId, messageIndex);
                  chatStoreState.syncHistory();
                  get().reset();
                }
              },
              onController(abortController) {
                ControllerPool.addController(
                  sessionId,
                  messageIndex,
                  abortController,
                );
              },
              ntesTraceId: ntesTraceId,
              setError: (type) => {
                chatStoreState.setError(type);
              },
            },
          );
        } else {
          let DEFAULT_MAX_TOKENS = 10240;
          if (
            [ChatModel.Gemini25, ChatModel.Gemini3Pro].includes(
              chatConfig.model,
            )
          ) {
            DEFAULT_MAX_TOKENS = 32000;
          }
          data.max_tokens = Math.max(data.max_tokens || 0, DEFAULT_MAX_TOKENS);
          // TEST: 调试用
          // data.messages = mockMessages as any;
          // data.messages = [
          //   data.messages[0],
          //   ...((mockMessages as any).slice(1))
          // ]

          let throttleTime = 0;
          let toolcallParsedIndex = 0;
          let parsedArgumentStr = '';
          let parsedTargetFile = '';
          let parsedCodeEdit = '';
          let parsedDiff = '';
          let inTargetFile = false;
          let inIsCreateFile = false;
          let inCodeEdit = false;
          let inDiff = false;

          const codebaseChatMode = useChatStore.getState().codebaseChatMode;
          if (
            session.data?.enablePlanMode &&
            !['openspec', 'speckit'].includes(codebaseChatMode || '')
          ) {
            injectTodoListToLastUserMessage(
              data.messages,
              session.data.todoList,
            );
          }

          // 如果是Deppseek模型，需要扁平化数据内容
          convertDeepseekMessages(chatConfig.model, data.messages);
          if (
            [ChatModel.GPT5, ChatModel.GPT51, ChatModel.GPT51Codex].includes(
              data.model as ChatModel,
            )
          ) {
            delete data.temperature;
          } else if ([ChatModel.Gemini3Pro].includes(data.model as ChatModel)) {
            data.messages[0].content += `\nNote:Don't repeat yourself`;
            data.temperature = 1;
          }
          // DEBUG: 调试用，校验是否前缀匹配
          // checkReusable({
          //   messages: data.messages,
          //   tools: data.tools || []
          // })
          data.codebase_chat_mode = codebaseChatMode || 'vibe';
          requestCodebaseChatStream(
            UserEvent.CODE_CHAT_CODEBASE,
            data,
            chatRequestUrl,
            {
              onMessage(
                content,
                done,
                toolCalls,
                totalTokens,
                completionTokens,
                promptTokens,
                cacheCreationInputTokens,
                cacheReadInputTokens,
                claude37Response,
                responseId,
              ) {
                get().setStreamRetryCount(0);

                if (toolCalls && toolCalls.length) {
                  // 只取第一个 tool call
                  toolCalls = toolCalls.slice(0, 1);
                }
                if (chatStoreState.isError) {
                  chatStoreState.setError(false);
                }
                if (done) {
                  // 模型返回后检测是否需要压缩
                  // 先检查请求期间是否发生过压缩（通过比较压缩摘要数量）
                  const currentSession = chatStoreState.currentSession();
                  const compressionSummaryCountNow = (
                    currentSession?.data?.messages || []
                  ).filter((msg) => msg.isCompressionSummary).length;
                  const hasCompressionOccurredDuringRequest =
                    compressionSummaryCountNow !==
                    compressionSummaryCountAtRequest;
                  try {
                    if (
                      toolCalls[0]?.function?.name === PlanTool.function.name
                    ) {
                      planReport(toolCalls[0]?.function?.arguments || '{}');
                    }
                  } catch {
                    userReporter.report({
                      event: UserEvent.CODE_CHAT_PLAN_PARSE_REPORT_ERROR,
                    });
                  }
                  console.log(
                    `promptTokens: ${promptTokens}, completionTokens: ${completionTokens}, cacheCreationInputTokens: ${cacheCreationInputTokens}, cacheReadInputTokens: ${cacheReadInputTokens}`,
                  );
                  if (attachs) {
                    const curAttachs = useChatAttach.getState()
                      .attachs as IMultiAttachment;
                    const dataSource = (curAttachs?.dataSource || []).filter(
                      (i) =>
                        [AttachType.CodeBase, AttachType.Docset].includes(
                          i.attachType,
                        ),
                    );
                    useChatAttach.getState().update({
                      dataSource: dataSource,
                      attachType: AttachType.MultiAttachment,
                    });
                  }
                  ControllerPool.remove(sessionId, messageIndex);
                  FeedbackPool.add(id);
                  const response: {
                    [propName: string]: boolean;
                  } = {};
                  const results: {
                    [propName: string]: {
                      path: string;
                      content: string;
                    };
                  } = {};
                  const allResponsed = false;
                  let isProcessing =
                    toolCalls.length && !allResponsed ? true : false;
                  // 遍历 toolCalls，如果非常规 tool，在 mcp tool 中找一下是否有对应的，恢复一下
                  const MCPServers = useMCPStore
                    .getState()
                    .getAvailableMCPServers();
                  toolCalls.forEach((tool) => {
                    if (!toolCallNames.includes(tool.function.name)) {
                      for (const server of MCPServers) {
                        const targetTool = (server.tools || []).find(
                          (t) => t.name === tool.function.name,
                        );
                        if (targetTool) {
                          tool.function = {
                            name: 'use_mcp_tool',
                            arguments: JSON.stringify({
                              server_name: server.name,
                              tool_name: tool.function.name,
                              arguments: tool.function.arguments,
                            }),
                          };
                          return;
                        }
                        const targetResource = (server.resources || []).find(
                          (t) => t.name === tool.function.name,
                        );
                        if (targetResource) {
                          tool.function = {
                            name: 'access_mcp_resource',
                            arguments: JSON.stringify({
                              server_name: server.name,
                              tool_name: tool.function.name,
                              arguments: tool.function.arguments,
                            }),
                          };
                          return;
                        }
                      }
                    }
                  });

                  // 用于隐藏多余的assistant消息
                  if (
                    toolCalls.find((toolCall) =>
                      [
                        'use_mcp_tool',
                        'access_mcp_resource',
                        'edit_file',
                        'reapply',
                        'run_terminal_cmd',
                        'replace_in_file',
                        'ask_user_question',
                      ].includes(toolCall.function.name),
                    )
                  ) {
                    isProcessing = false;
                  }
                  set((state) => {
                    state.isStreaming = false;
                    state.isProcessing = isProcessing;
                    state.isApplying = toolCalls.some((toolCall) =>
                      ['edit_file', 'reapply', 'replace_in_file'].includes(
                        toolCall.function.name,
                      ),
                    );
                  });
                  const curSessionId =
                    chatStoreState.currentSessionId as string;
                  chatStoreState.updateCurrentSession((session) => {
                    if (session._id !== curSessionId) return;
                    if (session.data?.messages) {
                      if (!cacheEnable || newTruncateStart >= 0) {
                        const lastMessage =
                          session.data.messages[
                          session.data.messages.length - 1
                          ];
                        if (lastMessage) {
                          lastMessage.reuseStart = false;
                        }
                      }
                      if (newTruncateStart >= 0) {
                        session.data.messages[newTruncateStart].truncateStart =
                          true;
                      }
                    }

                    onMessageToolCallResponse(
                      session,
                      content,
                      done,
                      toolCalls,
                      totalTokens,
                      completionTokens,
                    );
                    let groupTokens = completionTokens || 0;
                    if (previousTokens && totalTokens - previousTokens > 0) {
                      groupTokens = totalTokens - previousTokens;
                    }
                    session.data?.messages.push({
                      ...get().message,
                      ...claude37Response,
                      id,
                      content,
                      tool_calls: toolCalls || [],
                      processing: isProcessing,
                      total_tokens: totalTokens,
                      group_tokens: groupTokens,
                      completion_tokens: completionTokens,
                      response: response,
                      tool_result: results,
                      usage: {
                        prompt_tokens: promptTokens || 0,
                        completion_tokens: completionTokens || 0,
                        total_tokens: totalTokens || 0,
                        cache_creation_input_tokens:
                          cacheCreationInputTokens || 0,
                        cache_read_input_tokens: cacheReadInputTokens || 0,
                      },
                      isOutdatedTokens: hasCompressionOccurredDuringRequest,
                    });
                    chatStoreState.updateConsumedTokens({
                      model: model,
                      curSession: session,
                      promptTokens: promptTokens || 0,
                      completionTokens: completionTokens || 0,
                      cacheCreationInputTokens: cacheCreationInputTokens || 0,
                      cacheReadInputTokens: cacheReadInputTokens || 0,
                    });
                  });
                  if (MCPServers && MCPServers.length) {
                    let mcpServersUsed: string[] = [];
                    try {
                      mcpServersUsed = MCPServers.map((server) => server.name);
                    } catch {
                      mcpServersUsed = [];
                    }
                    userReporter.report({
                      event: UserEvent.CODE_CHAT_MCP_SESSION_TOKEN_USED,
                      extends: {
                        totalTokens:
                          promptTokens +
                          completionTokens +
                          cacheReadInputTokens +
                          cacheCreationInputTokens,
                        model: data.model,
                        mcp_servers: mcpServersUsed,
                      },
                    });
                  }
                  if (options.isMCPToolResponse) {
                    userReporter.report({
                      event: UserEvent.CODE_CHAT_MCP_MESSAGE_TOKEN_USED,
                      extends: {
                        totalTokens:
                          promptTokens +
                          completionTokens +
                          cacheReadInputTokens +
                          cacheCreationInputTokens,
                        model: data.model,
                        mcp_server: options.mcpServerUsed,
                      },
                    });
                  }
                  userReporter.report({
                    event: UserEvent.CODE_CHAT_TOKEN_USED,
                    extends: {
                      is_model_cache_enable:
                        !!chatModels[chatConfig.model]?.hasTokenCache,
                      model: chatConfig.model,
                      fallback_to_slide_window: fallbackToSlideWindow,
                      cache_enable: cacheEnable,
                      chat_type: chatType,
                      response_from: responseId ? responseId.slice(0, 8) : '',
                      prompt_tokens: promptTokens || 0,
                      completion_tokens: completionTokens || 0,
                      total_tokens: totalTokens || 0,
                      cache_creation_input_tokens:
                        cacheCreationInputTokens || 0,
                      cache_read_input_tokens: cacheReadInputTokens || 0,
                      cache_hit: cacheReadInputTokens > 0,
                      compression_enabled:
                        compressConfig.enable && compressConfig.visible,
                    },
                  });
                  if (toolCalls.length) {
                    if (!allResponsed) {
                      for (const tool of toolCalls) {
                        if (!response[tool.id]) {
                          let tool_params: any = {};
                          if (tool.function.arguments) {
                            try {
                              tool_params = JSON.parse(tool.function.arguments);
                            } catch (err) {
                              console.error(err);
                              tool_params = {};
                            }
                          }
                          if (
                            tool.function.name === 'use_mcp_tool' ||
                            tool.function.name === 'access_mcp_resource'
                          ) {
                            let params: any = {};
                            try {
                              params = JSON.parse(
                                tool.function.arguments || '{}',
                              );
                            } catch (err) {
                              console.error('解析MCP参数失败', err);
                              params = {};
                            }
                            let autoApprove = false;
                            if (
                              params &&
                              params.server_name &&
                              params.tool_name
                            ) {
                              const targetServer = MCPServers.find(
                                (server) => server.name === params.server_name,
                              );
                              if (targetServer && targetServer.tools) {
                                if (targetServer.autoApprove) {
                                  autoApprove = true;
                                } else if (targetServer.tools) {
                                  const targetTool = targetServer.tools.find(
                                    (tool) => tool.name === params.tool_name,
                                  );
                                  if (targetTool && targetTool.autoApprove) {
                                    autoApprove = true;
                                  }
                                }
                              } else {
                                const toolName =
                                  params?.tool_name?.toLowerCase?.();
                                for (const server of MCPServers) {
                                  const targetTool = (server?.tools || []).find(
                                    (tool) =>
                                      tool?.name?.toLowerCase?.() === toolName,
                                  );
                                  if (targetTool) {
                                    if (targetTool?.autoApprove) {
                                      autoApprove = true;
                                    }
                                    params.server_name = server.name;
                                    tool.function.arguments =
