import { OFFICE_BM_API_URL } from '../routes/CodeCoverage/const';
import { ChatMessage } from '../services';
import { REQUEST_TIMEOUT_NAME, useChatStore } from '../store/chat';
import { StreamError } from '../services/useChatStream';
import { Docset } from '../services/docsets';
import { cloneDeep } from 'lodash';
import { ChatRole } from '../types/chat';


export const LANGUAGE_TO_GRAPH_TYPE: Record<string, 'mermaid' | 'plantuml' | 'graphviz'> = {
  mermaid: 'mermaid',
  plantuml: 'plantuml',
  dot: 'graphviz',
  graphviz: 'graphviz',
};

/**
 * 根据 URL 参数生成隔离的存储键名
 * 实现主会话和 CM2 会话的数据隔离
 *
 * @param baseKey 基础存储键名
 * @returns 隔离后的存储键名
 */
export function getIsolatedStorageKey(baseKey: string): string {
  const urlParams = new URLSearchParams(window.location.search);
  const mode = urlParams.get('mode');
  const sessionId = urlParams.get('restoreSessionId');
  const panelId = urlParams.get('panelId');

  let storageKey: string;

  // 优先使用 sessionId 进行更精确的隔离
  if (mode && sessionId) {
    // 使用新的命名格式：cm_{mode}_codemaker-chat-store
    storageKey = `cm_${mode}_${baseKey}`;

    // 并行会话需要额外处理 panelId
    if (mode === 'panel' && panelId) {
      storageKey = `cm_${mode}_${panelId}_${baseKey}`;
    }
  } else if (mode === 'sidebar') {
    // 向后兼容：主会话模式
    storageKey = `${baseKey}-sidebar`;
  } else if (mode === 'newwindow') {
    // 向后兼容：CM2 模式
    storageKey = `${baseKey}-cm2`;
  } else if (mode === 'panel') {
    // 向后兼容：并行会话模式
    const parallelId = panelId || 'default';
    storageKey = `${baseKey}-panel-${parallelId}`;
  } else if (panelId) {
    // 兼容现有的 panelId 机制
    storageKey = `${baseKey}-panel-${panelId}`;
  } else {
    // 默认存储键名
    storageKey = baseKey;
  }

  return storageKey;
}

/**
 * 获取会话数据，同步插件端的数据读取逻辑
 * 针对并行会话提供优化的数据获取策略
 *
 * @param storageKey 存储键名
 * @param sessionId 会话ID
 * @returns 会话数据
 */
export function getSessionData(storageKey: string, sessionId: string): any {
  const urlParams = new URLSearchParams(window.location.search);
  const mode = urlParams.get('mode');

  try {
    // 同步插件端逻辑：从localStorage获取所有数据
    const allData = JSON.parse(localStorage.getItem(storageKey) || '{}');

    if (mode === 'panel') {
      // 并行会话使用sessionId区分数据，从allData中获取对应sessionId的数据
      const sessionData = allData[sessionId] || getDefaultSessionData();
      console.log('[Debug] Parallel session data:', { sessionId, sessionData, mode });
      return sessionData;
    } else {
      // 主会话和CM2直接使用自己独立的存储
      const sessionData = allData[sessionId] || getDefaultSessionData();
      console.log('[Debug] Session data loaded:', { sessionId, sessionData, mode });
      return sessionData;
    }
  } catch (error) {
    console.error('[Debug] Failed to load session data:', error);
    return getDefaultSessionData();
  }
}

/**
 * 清理 localStorage 中遗留的 panel（并行会话）旧存储数据
 * 使用 sessionStorage 的 flag 保证每次应用实例只执行一次，避免每次刷新重复扫描。
 * 后期可以移除
 */
export function cleanupLegacyPanelLocalStorage(): void {
  const FLAG_KEY = '__cm_panel_ls_cleaned__';

  // 同一个会话生命周期内只执行一次
  if (sessionStorage.getItem(FLAG_KEY)) return;

  try {
    const keysToRemove: string[] = [];
    const BASE_KEY = 'codemaker-chat-store';

    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (!key) continue;

      // 匹配所有 panel 相关的聊天 store key：
      // 1. cm_panel_*_codemaker-chat-store  （新格式）
      // 2. codemaker-chat-store-panel-*     （兼容格式）
      const isNewFormat =
        key.startsWith('cm_panel_') && key.endsWith(BASE_KEY);
      const isCompatFormat =
        key.startsWith(`${BASE_KEY}-panel-`);

      if (isNewFormat || isCompatFormat) {
        keysToRemove.push(key);
      }
    }

    if (keysToRemove.length > 0) {
      keysToRemove.forEach((key) => localStorage.removeItem(key));
      console.log(
        `[Init] Cleaned ${keysToRemove.length} legacy panel key(s) from localStorage:`,
        keysToRemove,
      );
    }

    // 标记本次会话已执行过清理
    sessionStorage.setItem(FLAG_KEY, '1');
  } catch (error) {
    console.warn('[Init] Failed to clean legacy panel localStorage keys:', error);
  }
}

/**
 * 获取默认会话数据结构
 */
function getDefaultSessionData(): any {
  return {
    messages: [],
    currentSessionId: null,
    chatType: 'default',
    // 其他默认字段...
  };
}

function pad(str: string | number): string {
  return +str >= 10 ? (str as string) : '0' + str;
}

/**
 * 时间格式函数
 *
 * @export
 * @param {any} [date=new Date()]
 * @param {string} [format='YYYY-MM-DD']
 * @returns
 */

export function DateFormat(d: Date | string | number, fmt?: string): string {
  let date = d || new Date();
  const format: string = fmt || 'YYYY-MM-DD';
  if (!date) {
    return '';
  }
  if (!(date instanceof Date)) {
    date = new Date(date);
  }
  const year = date.getFullYear();
  const month = date.getMonth() + 1;
  const day = date.getDate();
  const hour = date.getHours();
  const min = date.getMinutes();
  const sec = date.getSeconds();

  return format
    .replace('YYYY', '' + year)
    .replace('MM', pad(month))
    .replace('DD', pad(day))
    .replace('HH', pad(hour))
    .replace('mm', pad(min))
    .replace('ss', pad(sec));
}

export function toastErrorMessage(error: Error) {
  return `错误：${error.message}，请重试或联系我们：7896636`;
}

export function addString(
  textarea: HTMLTextAreaElement,
  str: string | ((prefix: string, postfix: string) => string),
) {
  const value = textarea.value;
  const selectionStart = textarea.selectionStart;
  const selectionEnd = textarea.selectionEnd;
  const prefix = value.slice(0, selectionStart);
  const postfix = value.slice(selectionEnd);
  const added = typeof str === 'function' ? str(prefix, postfix) : str;
  const nextValue = `${prefix}${added}${postfix}`;

  // https://github.com/facebook/react/issues/955
  // 为了保持光标暂时先用 setTimeout 解决。如果有问题的话可以参考：
  // https://github.com/facebook/react/issues/955#issuecomment-411558217
  // 将 selectionStart 作为一个状态，在 useLayoutEffect 中设置
  setTimeout(() => {
    textarea.selectionStart = selectionStart + added.length;
    textarea.selectionEnd = selectionStart + added.length;
  });
  return nextValue;
}

export function getErrorMessage(err: any) {
  // TODO: 根据错误类型提取错误信息，以及做定制化提示
  return (
    err?.status?.reson ||
    err?.response?.data?.msg ||
    err?.data?.msg ||
    err?.msg ||
    err?.message ||
    err?.detail ||
    ''
  );
}

/**
 * Detects Macintosh
 */
export function isMacOS(): boolean {
  if (typeof window !== 'undefined') {
    const userAgent = window.navigator.userAgent.toLocaleLowerCase();
    const macintosh = /iphone|ipad|ipod|macintosh/.test(userAgent);
    return !!macintosh;
  }
  return false;
}

export function isWin(): boolean {
  const platform = navigator.platform.toLowerCase();
  const userAgent = navigator.userAgent.toLowerCase();

  return (
    platform.indexOf('win') > -1 ||
    userAgent.indexOf('windows') > -1 ||
    userAgent.indexOf('win32') > -1 ||
    userAgent.indexOf('win64') > -1
  );
}

export function alphabeticalCompare(a: string, b: string) {
  return a.localeCompare(b, undefined, { numeric: true });
}

// 计算代码的行数和字符数
export function countGodeGenerate(code: string): {
  generate_lines: number;
  generate_chars: number;
} {
  if (!code) {
    return { generate_lines: 0, generate_chars: 0 };
  }
  const lines = code.split('\n').length;
  const chars = code.length;
  return { generate_lines: lines, generate_chars: chars };
}

export async function getBase64FromUrl(url: string): Promise<string> {
  try {
    // 使用代理去获取图片
    const newUrl = url.replace(
      'https://cm-img.s3v2.nie.netease.com',
      '/proxy/img',
    );
    // 提取文件扩展名
    const fileExtensionMatch = newUrl.match(/\.(jpeg|png|gif|webp|jfif|jpg)$/i);
    const fileExtension = fileExtensionMatch
      ? fileExtensionMatch[1].toLowerCase()
      : '';
    // 获取图片响应
    const response = await fetch(newUrl);

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    // 获取响应中的 Blob 数据
    const blob = await response.blob();

    // 获取响应的 Content-Type 头部信息，测试发现 Content-Type 无论什么图片都返回了 image/png ，前端先特殊处理
    // let contentType = response.headers.get('Content-Type');
    let contentType = 'image/png';
    switch (fileExtension) {
      case 'jpeg':
      case 'jpg':
      case 'png':
      case 'jfif':
      case 'webp':
        contentType = 'image/jpeg';
        // contentType = 'image/png';
        break;
      case 'gif':
        contentType = 'image/gif';
        break;
      // case 'webp':
      //   contentType = 'image/webp';
      //   break;
      default:
        throw new Error('Unable to determine content type');
    }

    const reader = new FileReader();

    const readerPromise = new Promise<string>((resolve, reject) => {
      reader.onloadend = () => {
        const base64Data = reader.result as string;
        const base64WithMime = `data:${contentType};base64,${base64Data.split(',')[1]
          }`;
        resolve(base64WithMime);
      };
      reader.onerror = () =>
        reject(new Error('Error reading Blob as Data URL'));
    });

    reader.readAsDataURL(blob);
    const base64Data = await readerPromise;

    return base64Data;
  } catch (error) {
    console.error('Failed to get Base64 from URL:', error);
    throw error;
  }
}

export function proxyImage(url: string) {
  // TODO: BM 图片需要特殊处理，目前没有更好的方案，先这样处理
  // 后续需要优化
  if (url.includes('brainmaker')) {
    if (url.includes('brainmaker-office')) {
      return url.replace(
        `https://brainmaker-office.netease.com/proxy/server`,
        `${OFFICE_BM_API_URL}/proxy/bm/api/v1`,
      );
    }
    return url.replace(
      `https://manage.brainmaker.netease.com/proxy/server`,
      '/proxy/bm',
    );
  }
  return url.replace('https://cm-img.s3v2.nie.netease.com', '/proxy/img');
}

