type GraphType = 'mermaid' | 'plantuml' | 'graphviz';

interface ExportGraphOptions {
  type: GraphType;
  chart: string;
}

export const exportGraphAsPng = async ({ type, chart }: ExportGraphOptions) => {
  try {
    // 处理不同类型的图表内容
    const processedChart = type === 'mermaid'
      ? `%%{init: {"theme": "dark", "themeVariables": {"background": "#000000", "primaryColor": "#303030", "secondaryColor": "#202020"}}}%%${chart}`
      : chart;

    // 映射图表类型到API端点
    const endpointMap: Record<GraphType, string> = {
      mermaid: 'mermaid',
      plantuml: 'plantuml',
      graphviz: 'graphviz'
    };

    const endpoint = endpointMap[type];
    if (!endpoint) {
      throw new Error(`Unsupported graph type: ${type}`);
    }

    const response = await fetch(`https://codemaker.nie.netease.com/kroki/${endpoint}/png`, {
      method: 'POST',
      headers: {
        'Content-Type': 'text/plain',
      },
      body: processedChart
    });

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const blob = await response.blob();

    // 使用Canvas处理图片
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        try {
          // 创建Canvas元素
          const canvas = document.createElement('canvas');
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            throw new Error('Failed to get canvas context');
          }

          // 设置Canvas尺寸与图片相同
          canvas.width = img.width;
          canvas.height = img.height;

          // 先填充黑色背景
          ctx.fillStyle = '#000000';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          // 然后绘制图片
          ctx.drawImage(img, 0, 0);

          // 转换为base64字符串
          const base64Data = canvas.toDataURL('image/png').split(',')[1];
          const timestamp = DateFormat(Date.now(), 'YYYYMMDDHHmmss');

          // 根据不同类型生成对应的文件名
          const typeLabels: Record<GraphType, string> = {
            mermaid: 'mermaid',
            plantuml: 'plantuml',
            graphviz: 'graphviz'
          };

          const filename = `${typeLabels[type]}-diagram-${timestamp}.png`;

          window.parent.postMessage(
            {
              type: 'EXPORT_FILE',
              data: { filename, content: base64Data },
            },
            '*'
          );
          resolve({ success: true });
        } catch (error) {
          reject(error);
        }
      };

      img.onerror = () => {
        reject(new Error('Failed to load image'));
      };

      // 从blob创建图片URL
      img.src = URL.createObjectURL(blob);
    });
  } catch (error) {
    console.error('Export failed:', error);
    throw error;
  }
};

